    step_kind = "instruction",
    zone_id = 245,
  }, {
    instruction = "Farm Quadav Charm and Quadav Augury Shell in Beadeaux, and obtain Coeurl Meat for the Jeuno key item trades.",
    map_grid = "L-11 / H-7 / G-7 / F-8 / E-10 / I-9 / F-6",
    notes = {"Enter Beadeaux from Pashhow Marshlands (L-11), use the Derfland > Beadeaux Survival Guide if available, or Unity warp to Pashhow Marshlands and run to the entrance.", "Quadav on the path can aggro by hearing under level 55; keep Sneak active.", "Follow the north/left wall to Map 2 via exit A at (H-7).", "On Map 2, follow the north/right wall to The Mute at (G-7) for Silence so The Afflictor will not Curse you.", "Continue to exit B at (F-8), then go south along the west/left wall to the ramp at (E-10). Use The Mute again if Silence wears before the next Afflictor.", "On the elevated path around (I-9), defeat De'Vyu Headhunter for Quadav Charm.", "Also on the elevated section, defeat Go'Bhu Gascon at (F-6) for Quadav Augury Shell.", "Coeurl Meat drops from Coeurls in Meriphataud Mountains or can be bought from the Auction House."},
