    verification_status = "draft",
    game_modes = {"ACE", "CW", "WEW"},
    source_url = "https://www.bg-wiki.com/ffxi/Promathia_Mission_5-3",
    steps = {{
    instruction = "Speak with Cid in the Metalworks at (H-8) to begin Three Paths. He asks you to choose a path, but all three can be completed in any order: Past Sins (Louverance's Path), The Pursuit of Paradise (Tenzen's Path), and Where Messengers Gather (Ulmia's Path). Prep ahead: two Snow Lilies if you do not have Mine Shaft 2716 Home Point, a Gold Key after the first Mine Shaft fight, Silent Oil and Prism Powder for Pso'Xja, optional Blackened Siredon for Head Wind, and Shu'Meyo Salt for Snoll Tzar.",
    map_grid = "H-8",
    notes = {},
    npc_name = "Cid",
    position = {},
    required_items = {"Snow Lily", "Gold Key", "Silent Oil", "Prism Powder", "Blackened Siredon", "Shu'Meyo Salt"},
    required_key_items = {"Envelope from Monberaux", "Delkfutt recognition device"},
    step_id = "start_with_cid",
    step_kind = "talk",
    zone_id = 237,
  }, {
    instruction = "Past Sins / Louverance's Path: speak with Despachiaire on the top floor of Tavnazian Safehold at (K-10). You may need to talk to him multiple times because he offers more than one cutscene. Then speak with Perih Vashai in Windurst Woods at (K-7), travel to Purgonorgo Isle in Bibiki Bay and check the ??? Warmachine at (H-11), and optionally speak with Yoran-Oran in Windurst Walls at (E-5).",
    map_grid = "K-10",
    notes = {},
    npc_name = "Despachiaire",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "louverance_path_openers",
    step_kind = "talk",
    zone_id = 26,
  }, {
    instruction = "A Century of Hardship: zone into Oldton Movalpolos for a cutscene, then reach Mine Shaft 2716. Fastest routes are Newton Movalpolos Home Point #1 or trading a Snow Lily to Tarnotik in Oldton Movalpolos at (K-10); buy Snow Lily from the Auction House or farm it from Uleguerand Tigers. Enter the mission battlefield A Century of Hardship, not an ENM. Buff inside, defeat Chekochuk, Trikotrak, Swipostik, Movamuq, and Bugbby; Silence works well on the mages. After the fight, speak to Cid, farm a Gold Key from Newton Movalpolos Moblins near the Oldton zone, return to Mine Shaft 2716, trade the Gold Key to the Shaft Entrance, then return to Cid to finish this path.",
    map_grid = "",
    notes = {},
    npc_name = "",
    object_name = "Shaft Entrance",
    position = {},
    required_items = {"Snow Lily", "Gold Key"},
    required_key_items = {},
    step_id = "century_of_hardship",
    step_kind = "fight",
    zone_id = 13,
  }, {
    instruction = "The Pursuit of Paradise / Tenzen's Path: check the ??? at La Theine Plateau (G-6) for the Carbuncle and Tenzen cutscene. Then enter Pso'Xja from Beaucedine Glacier tower (J-8), pass 16 one-way Stone Doors that may spawn Gargoyles, and check the Avatar Gate at the bottom. Continue Branded with Monberaux in Upper Jeuno (G-10) for Envelope from Monberaux, Pherimociel in Ru'Lude Gardens (G-6), then Monberaux again.",
    map_grid = "G-6",
    notes = {},
    npc_name = "",
    object_name = "???",
    position = {},
    required_items = {"Silent Oil", "Prism Powder"},
    required_key_items = {"Envelope from Monberaux", "Delkfutt recognition device"},
    step_id = "tenzen_path_openers",
    step_kind = "inspect",
    zone_id = 102,
  }, {
    instruction = "Pride and Honor: from Upper Jeuno, enter Batallia Downs and check the ??? near the town wall at (K-8/9), then check it again for the Delkfutt recognition device. In Lower Delkfutt's Tower first floor, check the Cermet Door at (H-5), defeat Disaster Idol, and check the door again. And the Compass Guides: enter Pso'Xja from Beaucedine Glacier (H-10), use Silent Oil and Prism Powder, follow the outer perimeter back near (I-8), pass west through the wall, drop through the hole, take the elevator, check the Avatar Gate, then return to Cid to finish Tenzen's Path.",
    map_grid = "H-5",
    notes = {},
    npc_name = "",
    object_name = "Cermet Door",
    position = {},
    required_items = {"Silent Oil", "Prism Powder"},
    required_key_items = {"Delkfutt recognition device"},
    step_id = "tenzen_delkfutt_and_compass",
    step_kind = "fight",
    zone_id = 184,
  }, {
    instruction = "Where Messengers Gather / Ulmia's Path: speak with Hinaree upstairs in Southern San d'Oria at (A-6), zone into Port San d'Oria, then speak with Chasalvige in Northern San d'Oria at (L-6). For Head Wind, speak with Kerutoto in Windurst Waters (J-8), then Yoran-Oran in Windurst Walls (E-5), then enter Boneyard Gully from Attohwa Chasm (H-6). Optional Blackened Siredon from Mithran Delicacies can slow Mithran Tracker TP gain. Click Dark Miasma and choose Head Wind, not Like the Wind. Buff inside, use Sleepga if available, and defeat Shikaree X, Shikaree Y, Shikaree Z, plus their pets; kill each pet's master first.",
    map_grid = "",
    notes = {},
    npc_name = "",
    object_name = "Dark Miasma",
    position = {},
    required_items = {"Blackened Siredon"},
    required_key_items = {},
    step_id = "ulmia_openers_and_head_wind",
    step_kind = "fight",
    zone_id = 8,
  }, {
    instruction = "Flames for the Dead: prep Shu'Meyo Salt from Bombs Away! with Buffalostalker Dodzbraz at Uleguerand Range (F-9); it delays Snoll Tzar's explosion by 20 seconds. Optional farm note: while in Uleguerand Range, collect Ahriman Tears for later and another Snow Lily from Uleguerand Tigers if you still need Mine Shaft access. Go to Uleguerand Range (J-9), drop through the hole near Home Point #2, enter Bearclaw Pinnacle, click the Wind Pillar, and choose Flames for the Dead. Buff inside, use salts one at a time after the message that Snoll Tzar shakes off the salt, and burn Snoll Tzar before the 45-second post-engage timer ejects you.",
    map_grid = "",
    notes = {},
    npc_name = "",
    object_name = "Wind Pillar",
    position = {},
    required_items = {"Shu'Meyo Salt", "Icarus Wing", "Opo-opo Necklace", "Sleeping Potion"},
    required_key_items = {},
    step_id = "flames_for_the_dead",
    step_kind = "fight",
    zone_id = 6,
  }, {
    instruction = "After completing Louverance's Path, Tenzen's Path, and Ulmia's Path, return to Cid at (H-8). If all three are complete, he gives the additional cutscene that moves you to Promathia Mission 6-1: For Whom the Verse is Sung. Optional after all three paths: speak with Perih Vashai in Windurst Woods (K-7) for Trust: Shikaree Z if you have a Windurst Trust permit and have not progressed past the available story window.",
    map_grid = "H-8",
    notes = {},
    npc_name = "Cid",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "complete_three_paths",
