    step_kind = "talk",
    zone_id = 237,
  }, {
    instruction = "Go to Sealion's Den at the bottom of the Tavnazian Safehold stone ramps near Home Point #2, opposite the aqueducts. Zone in for a cutscene, click the Iron Gate for another, board the airship, then click the airship door for the third cutscene and first fight setup.",
