    step_kind = "inspect",
    zone_id = 35,
  }, {
    instruction = "Climb to the 4th floor of a race tower and check the Ebon Panel twice: once for a cutscene/title and again for the race light key item. Matching towers: Light of Mea for Elvaan east, Light of Dem for Mithra west, Light of Holla for Tarutaru southwest, Light of Vahzl for Hume north, and Light of Al'Taieu for Galka southeast. Any Ebon Panel allows mission progress, but the matching tower gives the title cutscene.",
    map_grid = "race tower 4F",
    notes = {},
    npc_name = "",
    object_name = "Ebon Panel",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "retrieve_race_light",
    step_kind = "inspect",
    zone_id = 35,
  }, {
    instruction = "Reach the central first-floor area by looping east, north, then west to the elevator side. Qn'zdei door guards detect by true sight, are immune to Sleep, Lullaby, and Repose, and close doors if pulled off their pedestals; if the door closes, kill them and wait for the 5-minute respawn while auto-running at the door. Ascend, then collect Brand of Twilight to the south and Brand of Dawn to the north. Warp Distortions dismiss trusts; you can Warp out and Home Point back after each brand to save time.",
    map_grid = "central elevator",
    notes = {},
    npc_name = "",
    object_name = "Warp Distortion",
    position = {},
    required_items = {},
    required_key_items = {"Brand of Twilight", "Brand of Dawn"},
    step_id = "brands_of_dawn_twilight",
    step_kind = "inspect",
    zone_id = 35,
  }, {
    instruction = "Return to the central elevator and ascend until you reach the third floor. Check the Particle Gate for a cutscene, then check it again to enter the battlefield against four Ix'zdei pots. Two large pots are RDM type and two small pots are BLM type; all are Silence immune and highly Sleep resistant, usually requiring Elemental Seal to sleep. When low HP, a pot may try to return to its spawn and regenerate to full; Stun and weapon skills can stop it. After winning, cross the room and check the Luminous Convergence for a cutscene.",
    map_grid = "",
    notes = {},
    npc_name = "",
    object_name = "Particle Gate",
    position = {},
    required_items = {},
    required_key_items = {"Brand of Twilight", "Brand of Dawn"},
    step_id = "ixzdei_battlefield",
    step_kind = "fight",
    zone_id = 35,
  }, {
    instruction = "After the battle, head south to the Particle Gate, choose Leave the Garden of Ru'Hmet, then choose Yes to return to the Grand Palace. Head south and zone into Al'Taieu for the cutscene that finishes When Angels Fall and starts Dawn.",
    map_grid = "",
    notes = {},
    npc_name = "",
    object_name = "Particle Gate",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "exit_to_altaieu",
