    step_id = "promathia_battle",
    step_kind = "fight",
    zone_id = 36,
  }, {
    instruction = "After Promathia is defeated and Tear of Altana is awarded, wait until Japanese midnight before finishing the epilogue cutscenes. These can be done in any order: Hinaree in Southern San d'Oria (B-6), Uleguerand Range zone-in, Count Caffaule's Manor (B-6), Chipmy-Popmy in Port Windurst (C-8), ??? Warmachine on Purgonorgo Isle (H-11), Mhaura zone-in, Oldton Movalpolos zone-in, and Cid in Metalworks (H-8).",
