    step_id = "japanese_midnight_epilogues",
    step_kind = "prep_note",
    zone_id = 36,
  }, {
    instruction = "After all epilogue cutscenes, approach the Palace in Ru'Lude Gardens, then check the Marble Bridge door in Upper Jeuno at (F-7). Check the Marble Bridge door again to choose one ring: Rajas Ring, Sattva Ring, or Tamas Ring. You can continue cutscenes without choosing immediately.",
