  }, {
    instruction = "Head to the San d'Orian Embassy in Ru'Lude Gardens (H-9) and speak with Nelcabrit.",
    map_grid = "H-9",
    notes = {"If you already possess the Delkfutt Key (trade it to the door) or the Delkfutt key (no trading needed) then you may skip this climb:", "Head to Lower Delkfutt's Tower (E-8) Map 1 and enter the Basement by clicking the Cermet Door. Once you go through the door, proceed to (L-8) and click the Cermet Door for a cutscene. (Note: Another player using a key does not work.)", "Return to the San d'Orian Embassy in Ru'Lude Gardens and click the Door: San d'Orian Emb. for a cutscene to complete the Mission.", "If you do not possess the Key, start the climb process detailed below:", "You may be Tractored through this Basement door without the Key. If you decide to go this route, proceed to the \"Obtaining Delkfutt Key Short Way\" section.", "Otherwise, read the \"Obtaining Delkfutt Key\" section."},
    npc_name = "Nelcabrit",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "step_03_travel_head_to_the_san_dorian",
    step_kind = "travel",
    zone_id = 243,
  }, {
    instruction = "Head to Lower Delkfutt's Tower using the Survival Guide teleportation, Outpost warp, or Home Point warp.",
    map_grid = "F-6",
    notes = {},
    npc_name = "",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "step_04_travel_head_to_lower_delkfutts_tower",
    step_kind = "travel",
    target_name = "Lower Delkfutt's Tower entrance",
    zone_id = 126,
  }, {
    instruction = "Obtain a Delkfutt Key from Porphyrion on floor 10 of Delkfutt's Tower, use the Elevator to reach the Basement, then click the Cermet Door at (L-8).",
    map_grid = "H-7/H-8",
    notes = {"Preparation: set a Jeuno Home Point if possible, bring Sneak/Invisible or Prism Powder and Silent Oil, and bring Warp or a Warp item for the return.", "If you need maps, buy Map of Qufim Island and Map of Delkfutt's Tower from Promurouve in Lower Jeuno (H-7) or Rusese in Upper Jeuno (H-6).", "Travel from Port Jeuno to Qufim Island, then enter Lower Delkfutt's Tower at (F-6).", "Aggro safety: bats and Dancing Weapons detect sound, Goblins and Gigas detect sight, and Magic Pots/Dolls detect magic.", "Climb route summary: floor 1 right wall to stairs (E/F-6), floor 2 left wall to (I-9), floor 3 right wall to Teleporter (G-6), floor 4 right wall past two Teleporters to stairs (J-6).", "Continue: floor 5 door/hall at (I-7) then left wall to stairs (H-10), floor 6 right wall to Teleporter (J-10), floor 7 northwest to stairs (G-7), floor 8 left wall to stairs (J-7).", "Continue: floor 9 south to stairs (J-10), floor 8 again west to stairs (G-10) and do not fall down the hole, floor 9 again left wall to Teleporter (F-6), then floor 10.", "On floor 10, go southeast to the door at (H-7); Mimas guards the door and may need to be defeated before entering Porphyrion's room.", "Defeat Porphyrion for Delkfutt Key drops. He drops six keys; if more are needed, wait about 10 minutes for respawn.", "Trade Delkfutt Key to the Elevator around (H-8) in Porphyrion's room, then descend the long stairs to the Basement.", "In the Basement, head east into the large room and trade Delkfutt Key to the Cermet Door at (L-8) for the cutscene. If you have the Delkfutt key key item, interact instead.", "Return to the Door: San d'Orian Emb. in Ru'Lude Gardens for the completion cutscene, Rank 4, and 5,000 Gil. You may safely drop the Delkfutt Key afterward."},
    npc_name = "Porphyrion",
    position = {},
    required_items = {"Delkfutt Key"},
    required_key_items = {},
    step_id = "step_05_instruction_you_will_now_likely_need",
    step_kind = "instruction",
    zone_id = 158,
  }},
