    step_kind = "trade",
    zone_id = 245,
  }, {
    instruction = "Enter Davoi from Jugner Forest (G-12), cross west/north to Wall of Dark Arts at (G-7), enter Monastic Cavern, then inspect the Magicite at (F-6) for Magicite: Optistone.",
    map_grid = "G-12 / G-7 / F-6",
    notes = {"Use the Norvallen > Davoi Survival Guide if available, or Unity warp to Jugner Forest and run to the Davoi entrance.", "Orcs along the path can sight-aggro players under level 55 unless Invisible is active.", "Wolf Bats are level 25-29 and can hearing-aggro players under level 43 unless Sneak is active.", "The Wall of Dark Arts opens a menu; you must not be Invisible to click it, and nearby Orcs can aggro and interrupt the interaction.", "Past the Wall of Dark Arts is entrance #3 to Monastic Cavern.", "Monastic Cavern has no enemies on this route; walk to the end of the hall and inspect Magicite at (F-6)."},
    npc_name = "",
    object_name = "Davoi Magicite",
    position = {},
    required_items = {},
    required_key_items = {"Crest of Davoi", "Magicite: Optistone"},
    step_id = "step_09_davoi_magicite_optistone",
    step_kind = "interact",
    zone_id = 149,
  }, {
    instruction = "Enter Beadeaux from Pashhow Marshlands (L-11), follow the north/left wall to Map 2 at (H-7), turn left into Qulun Dome at (I-7), open the Door, and inspect the Magicite at (F-8) for Magicite: Aurastone.",
    map_grid = "L-11 / H-7 / I-7 / E-7 / F-8",
    notes = {"Use the Derfland > Beadeaux Survival Guide if available, or Unity warp to Pashhow Marshlands and run to the entrance.", "Quadav along this path can hearing-aggro players under level 42 unless Sneak is active.", "Open the Qulun Dome door and proceed into the hall to (E-7).", "If Silver bell, Coruscant rosary, and Black Matinee Necklace glow faintly, move closer and try the door again.", "Qulun Dome has no monsters on this route; inspect the Magicite at the end of the hall at (F-8)."},
    npc_name = "",
    object_name = "Beadeaux Magicite",
    position = {},
    required_items = {},
    required_key_items = {"Silver bell", "Coruscant rosary", "Black matinee necklace", "Magicite: Aurastone"},
    step_id = "step_10_beadeaux_magicite_aurastone",
    step_kind = "interact",
    zone_id = 148,
  }, {
    instruction = "Reach the Altar Room in Castle Oztroja from Meriphataud Mountains (L-8), then inspect the Magicite at (G-8) for Magicite: Orastone.",
    map_grid = "I-8 / J-8 / G-7 / I-7 / H-9 / G-10 / G-8",
    notes = {"Bring Silent Oil and Prism Powder; Yagudo on the path inside are up to level 49 and can sight-aggro players under level 68 unless Invisible is active.", "Bats can also aggro unless Sneak is active.", "Go through the Brass Door at (I-8) and go up the stairs to Map 3 via exit A at (J-8).", "One lever opens the Brass Door and one triggers the trapdoor. You cannot throw a lever unless you are standing on the trapdoor, and the correct lever changes every Vana'diel day.", "To avoid the trap, throw a lever and immediately run off the trapdoor during the delay.", "After exit A, go north then west to reach Map 7 via exit F at (G-7).", "From exit F, go north to enter Map 2 via exit I at (I-7).", "On Map 2, hug the right/West wall to reach the Yagudo Torch at (H-9).", "Click the Yagudo Torch to open the Brass Door; you must not be Invisible to click it, and nearby Yagudo can aggro and interrupt.", "Go through the door and go right/West to the Altar Room entrance at (G-10).", "If you spoke to Paya-Sabya and Muckvix, you will get the Fickblix cutscene; repeat missions may skip this scene.", "Inside the Altar Room, inspect the Magicite at (G-8) to receive Magicite: Orastone."},
    npc_name = "",
    object_name = "Castle Oztroja Magicite",
    position = {},
    required_items = {},
    required_key_items = {"Yagudo torch", "Magicite: Orastone"},
