    game_modes = {"ACE", "CW", "WEW"},
    source_url = "https://www.bg-wiki.com/ffxi/Windurst_Mission_4-1",
    steps = {{
    instruction = "To flag the Mission, head to the Windurstian Embassy in Jeuno, Ru'Lude Gardens (I-9) and speak with clerk Pakh Jatalfih. Then head to the back chamber to talk to the ambassador in a cutscene and receive the Archducal audience permit.",
    map_grid = "I-9",
    notes = {"If the mission or cutscene does not trigger, exchange crystals at a Conquest Overseer for rank points until your Rank bar allows Rank 4 missions. Morlepiche at Ru'Lude Gardens (H-10) accepts crystals in Jeuno; this mission starts at your Jeuno embassy, not at a Gate Guard.", "You will need to go through the door on the left side of the reception desk. The ambassador's office is in the end of the corridor. Click Door: Windurstian Emb. for the cutscene."},
