    step_kind = "instruction",
    zone_id = 147,
  }, {
    instruction = "Speak with Baudin at the west edge of Upper Jeuno (G-7), then trade him Coeurl Meat for Crest of Davoi.",
    map_grid = "G-7",
    notes = {"Baudin is the boy on the short steps upstairs from the stables."},
    npc_name = "Baudin",
    position = {},
    required_items = {"Coeurl Meat"},
    required_key_items = {"Crest of Davoi"},
    step_id = "step_06_key_item_crest_of_davoi",
    step_kind = "trade",
    zone_id = 244,
  }, {
