    first_target_name = "Leepe-Hoppe",
    first_map_grid = "",
    verification_status = "script_verified",
    game_modes = {"ACE", "CW", "WEW"},
    source_url = "https://www.bg-wiki.com/ffxi/Windurst_Mission_7-2",
    steps = {{
    instruction = "Talk to Leepe-Hoppe on the roof of the Rhinostery, located in the southern half of Windurst Waters near Home Point #3.",
    map_grid = "",
    notes = {"The correct dialogue involves Rukususu and Kerutoto."},
    npc_name = "Leepe-Hoppe",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "step_01_talk_talk_to_leepe_hoppe_on",
    step_kind = "talk",
    zone_id = 238,
  }, {
    instruction = "Talk to Kerutoto in the Rhinostery northern building for a cutscene.",
    map_grid = "",
    notes = {"You may need to talk to her over 3 times.", "The correct cutscene is the one where she talks about Leepe-Hoppe and Rukususu, not the Diabolos one.", "If she continues to give you the cutscene for Diabolos, accept the Quest and talk to her twice to activate the cutscene needed for this Mission.", "Optional: Talk to Vanono in Kazham at (G-7) for a brief message.", "Before minister Rukususu returned to the mainly-mainlands, I was able to giver her my report on my findings here in Elshimo. She was very pleased with all the lovely-wuvly discoveries that we had made. But we couldn't have done it without the help of adventurers like you!"},
    npc_name = "Kerutoto",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "step_02_talk_talk_to_kerutoto_in_the",
    step_kind = "talk",
    zone_id = 0,
  }, {
    instruction = "Talk to Romaa Mihgo in Kazham at (H-11) in Mihgo's Residence.",
    map_grid = "H-11",
    notes = {},
    npc_name = "Romaa Mihgo",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "step_03_talk_talk_to_romaa_mihgo_in",
    step_kind = "talk",
    zone_id = 250,
  }, {
    instruction = "Travel to the Temple of Uggalepih. You will have to kill Bonze Marberry for a Cursed Key ().",
    map_grid = "",
    notes = {"If you're in a party, each player will require one.", "The key won't drop if you already have one. Check your storage.", "Bonze Marberry is located on Map 3 near (J-9). It will drop 2 keys per kill, and respawns every 5 minutes. This NM uses Everyone's Rancor, therefore it is recommended to reset your Tonberry Hate if your Hate is high and you're fighting him at a low level.", "Quick travel options: Use the Yhoator Jungle Outpost Warp, Unity Warp or Survival Guide. → Run to the Bloodlet Spring Den of Rancor entrance at (J-7) → From this entrance of Den of Rancor, follow the right wall until you zone in Temple of Uggalepih. This will directly lead you on Map 3. → Go upstairs and follow the left wall. The NM will be in the room at (J-9)."},
    npc_name = "Bonze Marberry",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "step_04_travel_travel_to_the_temple_of",
    step_kind = "travel",
    zone_id = 159,
  }, {
    instruction = "After obtaining your Cursed Key, trade it to the Granite Door at (J-6) on the same map for a cutscene. You will receive Book of the Gods.",
    map_grid = "J-6",
    notes = {"Optional: Inspect three Tome of Magic.", "A workbook written by Iru-Kuiru. \"That place was most definitely cursed. It was as if each of us were having our strings pulled by some unseen force...\" \"The Goddess only knows what that power was. I knew fear like I had never known before, and was struck mindless with panic before the terror that lurked within these walls.\"", "A diary written by Iru-Kuiru. \"A letter has arrived from the homeland. The San d'Orian member of the Allied Expedition, Francmage M Mistalle, has lost his life to the curse...\" \"And then yesterday, my friend and fellow Allied explorer, Yow Rabntah, was taken from this world...\" \"I can feel the shadow closing in on me. I believe the darkness will claim me before I am able to finish this research. And I was so close to putting all the pieces of this legend together...\"", "A tome written on the subject of Fei'Yin. \"I would like to bring attention to the many small chambers that exist in the subterranean levels of the ruins of Fei'Yin.\" \"In each of these chambers stands an automaton. A golem, or giant, if you will. Were these golems given the task of sentry, or simply employed as servants?\" \"It is possible to conclude from the artifacts discovered in these ruins that it was once the abode of ancient people. One can further deduce from the evidence that this civilization was wiped out by some sudden calamity.\""},
    npc_name = "Cursed Key",
    position = {},
    required_items = {},
    required_key_items = {},
    step_id = "step_05_trade_after_obtaining_your_cursed_key",
    step_kind = "trade",
    zone_id = 0,
